import{_ as a,c as e,o as m,b as t}from"./app.aaa68922.js";const y='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 15","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 15","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","sans":"\u0939\u0943\u0926\u092F\u0947 \u091A\u093F\u0924\u094D\u0924\u0938\u0919\u094D\u0918\u091F\u094D\u091F\u093E\u0926\u094D\u0926\u0943\u0936\u094D\u092F\u0938\u094D\u0935\u093E\u092A\u0926\u0930\u094D\u0936\u0928\u092E\u094D","trans":"H\u1E5Bdaye cittasa\u1E45gha\u1E6D\u1E6D\u0101dd\u1E5B\u015Byasv\u0101padar\u015Banam","tags":"vim-1","date":"2021-02-12T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/1/15.md"}',p={},o=t('<div class="stanza"><a href="#s1.15" id="s1.15" class="num">1.15</a><div class="sans"><p>\u092F\u091A\u094D\u091A\u0947\u0926\u0902 \u0938\u0930\u094D\u0935\u0938\u094D\u092F \u0926\u0943\u0936\u094D\u092F\u0938\u094D\u092F \u0936\u0930\u0940\u0930\u0924\u092F\u093E \u0936\u0942\u0928\u094D\u092F\u093E\u0928\u094D\u0924\u0938\u094D\u092F \u091A \u0926\u0943\u0936\u094D\u092F\u0924\u092F\u0948\u0915\u0930\u0942\u092A\u0902 \u092A\u094D\u0930\u0915\u093E\u0936\u0928\u092E\u0941\u0915\u094D\u0924\u0902 \u0928\u0948\u0924\u0926\u094D\u0926\u0941\u0930\u094D\u0918\u091F\u092E\u092A\u093F \u0924\u0941\u2014</p><blockquote><p><strong>\u0939\u0943\u0926\u092F\u0947 \u091A\u093F\u0924\u094D\u0924\u0938\u0919\u094D\u0918\u091F\u094D\u091F\u093E\u0926\u094D\u0926\u0943\u0936\u094D\u092F\u0938\u094D\u0935\u093E\u092A\u0926\u0930\u094D\u0936\u0928\u092E\u094D\u0965\u0967\u096B\u0965</strong></p></blockquote><p>\u0935\u093F\u0936\u094D\u0935\u092A\u094D\u0930\u0924\u093F\u0937\u094D\u0920\u093E\u0938\u094D\u0925\u093E\u0928\u0924\u094D\u0935\u093E\u091A\u094D\u091A\u093F\u0924\u094D\u092A\u094D\u0930\u0915\u093E\u0936\u094B \u0939\u0943\u0926\u092F\u0902 \u0924\u0924\u094D\u0930 \u091A\u093F\u0924\u094D\u0924\u0938\u0919\u094D\u0918\u091F\u094D\u091F\u093E\u091A\u094D\u091A\u0932\u0924\u0936\u094D\u091A\u0932\u0924\u0938\u094D\u0924\u0926\u0947\u0915\u093E\u0917\u094D\u0930\u092D\u093E\u0935\u0924\u093E\u0926\u094D\u0926\u0943\u0936\u094D\u092F\u0938\u094D\u092F \u0928\u0940\u0932\u0926\u0947\u0939\u092A\u094D\u0930\u093E\u0923\u092C\u0941\u0926\u094D\u0927\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u0903 \u0938\u094D\u0935\u093E\u092A\u0938\u094D\u092F \u091A\u0948\u0924\u0926\u092D\u093E\u0935\u0930\u0942\u092A\u0938\u094D\u092F \u0936\u0942\u0928\u094D\u092F\u0938\u094D\u092F \u0926\u0930\u094D\u0936\u0928\u0902 \u0924\u094D\u092F\u0915\u094D\u0924\u0917\u094D\u0930\u093E\u0939\u094D\u092F\u0917\u094D\u0930\u093E\u0939\u0915\u0935\u093F\u092D\u0947\u0926\u0947\u0928 \u092F\u0925\u093E\u0935\u0938\u094D\u0924\u0941 \u0938\u094D\u0935\u093E\u0919\u094D\u0917\u0915\u0932\u094D\u092A\u0924\u092F\u093E \u092A\u094D\u0930\u0915\u093E\u0936\u0928\u0902 \u092D\u0935\u0924\u093F\u0964 \u091A\u093F\u0924\u094D\u092A\u094D\u0930\u0915\u093E\u0936\u0924\u093E\u092E\u092D\u093F\u0928\u093F\u0935\u093F\u0936\u092E\u093E\u0928\u0902 \u0939\u093F \u091A\u093F\u0924\u094D\u0924\u0902 \u0924\u0926\u093E\u091A\u094D\u091B\u0941\u0930\u093F\u0924\u092E\u0947\u0935 \u0935\u093F\u0936\u094D\u0935\u0902 \u092A\u0936\u094D\u092F\u0924\u093F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u0939\u0943\u0926\u094D\u092F\u093E\u0915\u093E\u0936\u0947 \u0928\u093F\u0932\u0940\u0928\u093E\u0915\u094D\u0937\u0903 \u092A\u0926\u094D\u092E\u0938\u092E\u094D\u092A\u0941\u091F\u092E\u0927\u094D\u092F\u0917\u0903 \u0905\u0928\u0928\u094D\u092F\u091A\u0947\u0924\u093E\u0903 \u0938\u0941\u092D\u0917\u0947 \u092A\u0930\u0902 \u0938\u094C\u092D\u093E\u0917\u094D\u092F\u092E\u093E\u092A\u094D\u0928\u0941\u092F\u093E\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092A\u0930\u0902 \u0939\u094D\u092F\u0924\u094D\u0930 \u0938\u094C\u092D\u093E\u0917\u094D\u092F\u0902 \u0935\u093F\u0936\u094D\u0935\u0947\u0936\u094D\u0935\u0930\u0924\u093E\u092A\u0924\u094D\u0924\u093F\u0903\u0964 \u0924\u0924\u094D\u0924\u094D\u0935\u0935\u0943\u0924\u094D\u0924\u093F\u0938\u092E\u093E\u092A\u0928\u094D\u0928\u0902 \u092E\u0939\u093E\u092F\u094B\u0917\u093F\u0928\u092E\u0941\u0926\u094D\u0926\u093F\u0936\u094D\u092F \u0936\u094D\u0930\u0940\u092E\u0924\u094D\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947\u093D\u092A\u093F</p><blockquote><p>\u0938 \u091A \u0938\u0930\u094D\u0935\u0947\u0937\u0941 \u092D\u0942\u0924\u0947\u0937\u0941 \u092D\u093E\u0935\u0924\u0924\u094D\u0924\u094D\u0935\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0947\u0937\u0941 \u091A \u0938\u094D\u0925\u093E\u0935\u0930\u0902 \u091C\u0919\u094D\u0917\u092E\u0902 \u091A\u0948\u0935 \u091A\u0947\u0924\u0928\u093E\u091A\u0947\u0924\u0928\u0938\u094D\u0925\u093F\u0924\u092E\u094D\u0965<br> \u0906\u0927\u094D\u0935\u093E\u0928\u0902 \u0935\u094D\u092F\u093E\u092A\u094D\u092F \u0938\u0930\u094D\u0935\u0902 \u0924\u0941 \u0938\u093E\u092E\u0930\u0938\u094D\u092F\u0947\u0928 \u0938\u0902\u0938\u094D\u0925\u093F\u0924\u0903\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0924\u0941</p><blockquote><p>\u0924\u0925\u093E \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u094D\u092F\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u093E\u0924\u094D\u0938\u0930\u094D\u0935\u0924\u094D\u0930\u0948\u0935\u0902 \u092D\u0935\u093F\u0937\u094D\u092F\u0924\u093F</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u0948\u0935\u0948\u0924\u0924\u094D\u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0965\u0967\u096B\u0965</p></div><hr><div class="trans"><p>Yacceda\u1E41 sarvasya d\u1E5B\u015Byasya \u015Bar\u012Bratay\u0101 \u015B\u016Bny\u0101ntasya ca d\u1E5B\u015Byatayaikar\u016Bpa\u1E41 prak\u0101\u015Banamukta\u1E41 naitaddurgha\u1E6Damapi tu\u2014</p><blockquote><p><strong>H\u1E5Bdaye cittasa\u1E45gha\u1E6D\u1E6D\u0101dd\u1E5B\u015Byasv\u0101padar\u015Banam||15||</strong></p></blockquote><p>Vi\u015Bvaprati\u1E63\u1E6Dh\u0101sth\u0101natv\u0101ccitprak\u0101\u015Bo h\u1E5Bdaya\u1E41 tatra cittasa\u1E45gha\u1E6D\u1E6D\u0101ccalata\u015Bcalatastadek\u0101grabh\u0101vat\u0101dd\u1E5B\u015Byasya n\u012Bladehapr\u0101\u1E47abuddhy\u0101tmana\u1E25 sv\u0101pasya caitadabh\u0101var\u016Bpasya \u015B\u016Bnyasya dar\u015Bana\u1E41 tyaktagr\u0101hyagr\u0101hakavibhedena yath\u0101vastu sv\u0101\u1E45gakalpatay\u0101 prak\u0101\u015Bana\u1E41 bhavati| Citprak\u0101\u015Bat\u0101mabhinivi\u015Bam\u0101na\u1E41 hi citta\u1E41 tad\u0101cchuritameva vi\u015Bva\u1E41 pa\u015Byati| Tadukta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>H\u1E5Bdy\u0101k\u0101\u015Be nil\u012Bn\u0101k\u1E63a\u1E25 padmasampu\u1E6Damadhyaga\u1E25 Ananyacet\u0101\u1E25 subhage para\u1E41 saubh\u0101gyam\u0101pnuy\u0101t||</p></blockquote><p>iti| Para\u1E41 hyatra saubh\u0101gya\u1E41 vi\u015Bve\u015Bvarat\u0101patti\u1E25| Tattvav\u1E5Bttisam\u0101panna\u1E41 mah\u0101yoginamuddi\u015Bya \u015Br\u012Bmatsvacchande&#39;pi</p><blockquote><p>Sa ca sarve\u1E63u bh\u016Bte\u1E63u bh\u0101vatattvendriye\u1E63u ca Sth\u0101vara\u1E41 ja\u1E45gama\u1E41 caiva cetan\u0101cetanasthitam| \u0100dhv\u0101na\u1E41 vy\u0101pya sarva\u1E41 tu s\u0101marasyena sa\u1E41sthita\u1E25|</p></blockquote><p>iti| Spande tu</p><blockquote><p>Tath\u0101 sv\u0101tmanyadhi\u1E63\u1E6Dh\u0101n\u0101tsarvatraiva\u1E41 bhavi\u1E63yati||</p></blockquote><p>ityanenaivaitatsa\u1E45g\u1E5Bh\u012Btam||15||</p></div><hr><p>\u042D\u0442\u043E <em>(idam)</em>, \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u043C <em>(yad ca)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> [\u043A\u0430\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B], \u0442.\u0435. [\u0447\u0442\u043E] (\u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435) \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(prak\u0101\u015Banam)</em> \u0432\u0441\u0435\u0445 <em>(sarvasya)</em> \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u0432 [\u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445] <em>(d\u1E5B\u015Byasya)</em> \u2014\u0442\u0430\u043A\u0436\u0435 <em>(ca)</em> [\u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u043C\u043E\u0435] \u043A\u0430\u043A \u0444\u0435\u043D\u043E\u043C\u0435\u043D <em>(d\u1E5B\u015Byatay\u0101)</em>, [\u0442\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u0442\u044C,] \u0434\u0430\u0436\u0435 \u0442\u043E, \u0447\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(antasya)</em> [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F] \u043F\u0443\u0441\u0442\u043E\u0442\u044B <em>(\u015B\u016Bnya)</em>\u2014 \u043A\u0430\u043A [\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E] \u0442\u0435\u043B\u0430 <em>(\u015Bar\u012Bratay\u0101)</em> \u0435\u0434\u0438\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E --\u0442.\u0435. \u043A\u0430\u043A \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0444\u043E\u0440\u043C\u0443-- <em>(eka-r\u016Bpam)</em>, \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F --\u0442.\u0435. \u044D\u0442\u043E \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F-- <em>(na etad)</em> \u0442\u0440\u0443\u0434\u043D\u043E \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u043C\u044B\u043C <em>(durgha\u1E6Dam)</em>, \u0430 \u0441\u043A\u043E\u0440\u0435\u0435 <em>(api tu)</em><sup>1</sup>\u2014</p><blockquote><p><strong>\u0427\u0435\u0440\u0435\u0437 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(sa\u1E45gha\u1E6D\u1E6D\u0101t)</em> \u0443\u043C\u0430 <em>(citta)</em> \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(h\u1E5Bdaye)</em> \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em> [\u0432\u0441\u0435\u0445] \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u0432 [\u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445] <em>(d\u1E5B\u015Bya)</em> [\u0438 \u0434\u0430\u0436\u0435] \u043F\u0443\u0441\u0442\u043E\u0442\u044B <em>(sv\u0101pa)</em> [\u043A\u0430\u043A \u043E\u043D\u0438 \u0435\u0441\u0442\u044C \u0432 \u0438\u0445 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435]||15||</strong></p></blockquote><p>[\u0417\u0434\u0435\u0441\u044C] h\u1E5Bdaya --\u044F\u0434\u0440\u043E, \u0438\u043B\u0438 \u0441\u0435\u0440\u0434\u0446\u0435-- <em>(y\u0101... s\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0421\u0432\u0435\u0442\u043E\u043C <em>(prak\u0101\u015Ba\u1E25)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em> \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043E\u0439 <em>(prati\u1E63\u1E6Dh\u0101-sth\u0101natv\u0101t)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>. \u0412 \u044D\u0442\u043E\u043C [h\u1E5Bdaya] <em>(tatra)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F <em>(sa\u1E45gha\u1E6D\u1E6D\u0101t)</em> \u0443\u043C\u0430 <em>(citta)</em> \u2014\u0442.\u0435 \u043F\u0443\u0442\u0435\u043C \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F <em>(bh\u0101vat\u0101t)</em> \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438 <em>(ek\u0101gra)</em> \u0431\u0435\u0441\u043F\u043E\u043A\u043E\u0439\u043D\u043E\u0433\u043E [\u0443\u043C\u0430] <em>(calata\u1E25 calata\u1E25)</em> \u043D\u0430 \u0422\u043E\u043C --\u043D\u0430 \u0421\u0432\u0435\u0442\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(tad)</em>\u2014, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavati)</em> dar\u015Bana <em>(dar\u015Banam)</em>, [\u0438\u043B\u0438] \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(prak\u0101\u015Banam)</em> \u0432\u0441\u0435\u0445 \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u0432 [\u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445] <em>(d\u1E5B\u015Byasya)</em> \u2014\u0442.\u0435. \u0441\u0438\u043D\u0435\u0433\u043E <em>(n\u012Bla)</em>, \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430 <em>(deha)</em>, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em> [\u0438] \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 <em>(buddhi-\u0101tmana\u1E25)</em>\u2014, \u0438 <em>(ca)</em> [\u0434\u0430\u0436\u0435] of sv\u0101pa <em>(sv\u0101pasya)</em>, [\u0438\u043B\u0438] \u043F\u0443\u0441\u0442\u043E\u0442\u044B <em>(\u015B\u016Bnyasya)</em> \u2014\u0442.\u0435. \u0442\u043E\u0433\u043E, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(r\u016Bpasya)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 <em>(abh\u0101va)</em> \u044D\u0442\u043E\u0433\u043E --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u0432 \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E-- <em>(etad)</em>\u2014, \u043A\u0430\u043A <em>(kalpatay\u0101)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(sva)</em> \u0442\u0435\u043B\u0430 <em>(a\u1E45ga)</em> \u2014\u0442.\u0435. [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u0445 \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u0432 \u0438 \u043F\u0443\u0441\u0442\u043E\u0442\u044B] \u0442\u0430\u043A\u0438\u043C\u0438, \u043A\u0430\u043A\u0438\u043C\u0438 \u043E\u043D\u0438 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(yath\u0101-vastu)</em>, \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u043C\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439 <em>(tyakta... vibhedena)</em> \u043C\u0435\u0436\u0434\u0443 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C <em>(gr\u0101haka)</em> [\u0438] \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C <em>(gr\u0101hya)</em>\u2014<sup>2</sup>|</p><p>\u0411\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E <em>(hi)</em>, \u0443\u043C <em>(cittam)</em>, \u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0439 <em>(abhinivi\u015Bam\u0101nam)</em> \u0432 \u0421\u0432\u0435\u0442 <em>(prak\u0101\u015Bat\u0101m)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>, \u0432\u0438\u0434\u0438\u0442 <em>(pa\u015Byati)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bvam)</em> \u043A\u0430\u043A \u043F\u0440\u043E\u043F\u0438\u0442\u0430\u043D\u043D\u0443\u044E <em>(\u0101cchuritam eva)</em> \u044D\u0442\u0438\u043C [\u0421\u0432\u0435\u0442\u043E\u043C] <em>(tad)</em>|</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0431\u044B\u043B\u043E \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 <em>(\u015Br\u012B)</em> Vij\xF1\u0101nabhairava <em>(vij\xF1\u0101nabhairave)</em> [\u0442\u0430\u043A\u0436\u0435]:</p><blockquote><p>&quot;\u041E\u043D, \u0447\u044C\u0438 \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u044F <em>(ak\u1E63a\u1E25)</em> \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u044B <em>(nil\u012Bna)</em> \u043D\u0430 \u044D\u0444\u0438\u0440\u0435, \u0438\u043B\u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 <em>(\u0101k\u0101\u015Be)</em> \u0432\u043D\u0443\u0442\u0440\u0438 \u0441\u0435\u0440\u0434\u0446\u0430 --\u0442.\u0435. \u0432\u043D\u0443\u0442\u0440\u0438 \u043B\u043E\u0442\u043E\u0441\u0430 \u0441\u0435\u0440\u0434\u0446\u0430-- <em>(h\u1E5Bdi)</em>, \u043A\u0442\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(ga\u1E25)</em> \u043F\u043E\u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 <em>(madhya)</em> [\u0434\u0432\u0443\u0445] \u043F\u043E\u043B\u0443\u0441\u0444\u0435\u0440\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0447\u0430\u0448 <em>(sampu\u1E6Da)</em> [\u044D\u0442\u043E\u0433\u043E] \u043B\u043E\u0442\u043E\u0441\u0430 <em>(padma)</em> --\u0442.\u0435. \u0442\u0430\u043C, \u0433\u0434\u0435 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0412\u044B\u0441\u0448\u0435\u0435 \u042F--, \u0438 \u0447\u0435\u0439 \u0443\u043C <em>(cet\u0101\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0435\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C --\u0442.\u0435. \u0447\u0435\u0439 \u0443\u043C \u0441\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043D \u0438 \u0432\u0438\u0434\u0438\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E \u043A\u0430\u043A \u043F\u0440\u043E\u043D\u0438\u0437\u0430\u043D\u043D\u0443\u044E \u0421\u0432\u0435\u0442\u043E\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(ananya)</em>, \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 <em>(\u0101pnuy\u0101t)</em> \u043D\u0430\u0438\u0432\u044B\u0441\u0448\u0443\u044E <em>(param)</em> \u0443\u0434\u0430\u0447\u0443, \u0438\u043B\u0438 \u0431\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u0438\u0435 <em>(saubh\u0101gyam)</em>, \u041E \u041F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u0430\u044F <em>(subhage... iti)</em>&quot;||</p></blockquote><p>\u0417\u0434\u0435\u0441\u044C <em>(atra)</em> \u0432\u044B\u0441\u0448\u0430\u044F <em>(param)</em> \u0443\u0434\u0430\u0447\u0430 <em>(saubh\u0101gyam)</em> \u2014 [\u044D\u0442\u043E] \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em> \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 <em>(\u0101patti\u1E25)</em> \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u0430 <em>(\u012B\u015Bvarat\u0101)</em> \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>|</p><p>\u0427\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F <em>(uddi\u015Bya)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E <em>(mah\u0101)</em> Yog\u012B <em>(yoginam)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u0441\u0442\u0438\u0433 <em>(sam\u0101pannam)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(v\u1E5Btti)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 <em>(tattva)</em>, \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 <em>(\u015Br\u012Bmad)</em> Svacchandatantra <em>(svacchande)</em> [\u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E] \u0442\u0430\u043A\u0436\u0435 <em>(api)</em>:</p><blockquote><p>&quot;\u041E\u043D <em>(sa\u1E25 ca)</em>, [\u043A\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0430 \u0441 Bhairava --\u0442.\u0435. \u0441 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C--], \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044F <em>(vy\u0101pya)</em> \u0432\u0441\u0435 <em>(tu sarvam)</em> [\u0448\u0435\u0441\u0442\u044C] \u043F\u0443\u0442\u0435\u0439 <em>(\u0101dhv\u0101nam)</em>, \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 <em>(sthitam)</em> [\u0432] \u0431\u0435\u0441\u0447\u0443\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u0445 <em>(acetanam)</em>, [\u0438\u043B\u0438] \u043D\u0435\u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0435\u043D\u043D\u044B\u0445 <em>(sth\u0101varam)</em> \u0438 <em>(ca eva)</em> [\u0432] \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u0445 <em>(cetana)</em>, [\u0438\u043B\u0438] \u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0435\u043D\u043D\u044B\u0445 <em>(ja\u1E45gamam)</em> --\u0442.\u0435 \u0432\u043E \u0432\u0441\u0435\u043C, \u0447\u0442\u043E \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F \u0438 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u043D\u0435\u043F\u043E\u0434\u0432\u0438\u0436\u043D\u044B\u043C \u0432\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439--, \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(sa\u1E41sthita\u1E25)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0441 Bhairava <em>(s\u0101marasyena)</em> \u0432\u043E \u0432\u0441\u0435\u0445 <em>(sarve\u1E63u)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u0445 <em>(bh\u016Bte\u1E63u)</em>, \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u0445 <em>(bh\u0101va)</em>, \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F\u0445 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(tattva)</em> \u0438 <em>(ca)</em> indriya-s --\u0434\u0435\u0441\u044F\u0442\u0438 \u0421\u0438\u043B\u0430\u0445 \u0412\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F \u0438 \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F-- <em>(indriye\u1E63u... iti)</em><sup>4</sup>&quot; [\u0421\u043C. IV, 310 \u0432 Svacchandatantra]</p></blockquote><p>\u0412 Spandak\u0101rik\u0101-s <em>(spande tu)</em> \u044D\u0442\u043E [\u0436\u0435 \u0443\u0447\u0435\u043D\u0438\u0435] <em>(etad)</em> \u0431\u044B\u043B\u043E \u0440\u0435\u0437\u044E\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u0432 \u044D\u0442\u043E\u0439 [\u0447\u0430\u0441\u0442\u0438 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430] <em>(anena eva)</em>:</p><blockquote><p>&quot;... \u043F\u043E\u044D\u0442\u043E\u043C\u0443 [\u0442\u0430\u043A\u0436\u0435] <em>(tath\u0101)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044F <em>(adhi\u1E63\u1E6Dh\u0101n\u0101t)</em> \u0432 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(sva)</em> \u0412\u044B\u0441\u0448\u0435\u043C \u042F <em>(\u0101tmani)</em>, \u0431\u0443\u0434\u0435\u0442 <em>(bhavi\u1E63yati)</em> \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E <em>(evam)</em> [\u0432\u0441\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435] \u043F\u043E\u0432\u0441\u0435\u043C\u0435\u0441\u0442\u043D\u043E <em>(sarvatra... iti)</em>&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s III, 7]</p></blockquote><p>||15||</p><hr><ol><li><p>\u0425\u043E\u0442\u044F \u043A\u0430\u0436\u0435\u0442\u0441\u044F, \u0447\u0442\u043E \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0430 \u0448\u0443\u0442\u0438\u0442, \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u043E\u043D \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u0432\u0441\u0435\u0440\u044C\u0435\u0437. \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043D\u0435 \u0442\u0440\u0443\u0434\u043D\u043E \u0434\u043E\u0441\u0442\u0438\u0447\u044C, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 &quot;\u043A\u0430\u0436\u0434\u044B\u0439 \u2014 \u044D\u0442\u043E \u0432\u0441\u0435\u0433\u0434\u0430 \u0413\u043E\u0441\u043F\u043E\u0434\u044C&quot;, \u0438 \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 \u0432 \u044D\u0442\u043E\u043C. \u041E\u0434\u043D\u0430\u043A\u043E, \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0437\u0430\u0434\u0430\u0447\u0430 \u043A\u0430\u0436\u0435\u0442\u0441\u044F \u043D\u0435\u0432\u044B\u043F\u043E\u043B\u043D\u0438\u043C\u043E\u0439 \u0438\u0437-\u0437\u0430 \u0435\u0433\u043E \u0442\u044F\u0436\u0435\u043B\u043E\u0433\u043E \u0431\u0440\u0435\u043C\u0435\u043D\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u044D\u0442\u043E \u0441\u043F\u043E\u0441\u043E\u0431 \u0432\u044B\u0440\u0430\u0436\u0430\u0442\u044C\u0441\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E - \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0421\u0430\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u0432\u0435\u0440\u044F\u0449\u0438\u0439 \u0432 \u0442\u043E, \u0447\u0442\u043E \u041E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u043C M\u0101y\u0101&quot; \u0438 \u0442\u043E\u043C \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u0435\u043D, \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0441\u0442\u0430\u0442\u044C &quot;\u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E&quot; \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0442\u0430\u043A\u0436\u0435. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043D\u0435\u0442 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0438\u044F \u0438\u043B\u0438 \u043F\u0440\u0435\u0443\u0432\u0435\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043B \u043C\u0443\u0434\u0440\u0435\u0446. \u0415\u0441\u0442\u044C \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u043E, \u0447\u0442\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u043E\u0431\u043C\u0430\u043D\u044B\u0432\u0430\u0435\u0442 \u0421\u0435\u0431\u044F, \u0447\u0442\u043E \u0437\u0430\u0434\u0430\u0447\u0430 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F \u0432\u0441\u0435\u0445 \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u0432 \u043A\u0430\u043A \u0441\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0442\u0435\u043B\u043E, \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 \u043A\u0430\u043A \u043D\u0435\u0432\u044B\u043F\u043E\u043B\u043D\u0438\u043C\u0430\u044F. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043F\u0435\u0440\u0441\u0442\u0430\u043D\u044C \u043E\u0431\u043C\u0430\u043D\u044B\u0432\u0430\u0442\u044C \u0441\u0435\u0431\u044F, \u0434\u043E\u0440\u043E\u0433\u043E\u0439 \u041F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C, \u0438 \u043F\u0440\u043E\u0441\u043D\u0438\u0441\u044C! \u0412 \u043E\u0431\u0449\u0435\u043C, \u0435\u0441\u043B\u0438 \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044C \u0432\u0441\u0435 \u0435\u0449\u0435 &quot;\u0434\u0443\u043C\u0430\u0435\u0442&quot;, \u0447\u0442\u043E \u0432\u0441\u0435, \u0447\u0442\u043E \u043C\u0443\u0434\u0440\u0435\u0446 \u043F\u0438\u0448\u0435\u0442, \u0441\u0432\u044F\u0437\u0430\u043D\u043E \u0441 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C, \u0441 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u044B\u043C Yog\u012B \u0438 \u0442.\u0434., \u043E\u0442\u043B\u0438\u0447\u043D\u044B\u0445 \u043E\u0442 \u043D\u0435\u0433\u043E/\u043D\u0435\u0435, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044C \u0435\u0449\u0435 \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u043F\u043E\u043D\u044F\u043B \u043E\u0431 \u044D\u0442\u043E\u043C \u043F\u0438\u0441\u0430\u043D\u0438\u0438. \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u043C\u0435\u0442\u0438\u0442\u044C, \u0447\u0442\u043E \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044C \u043D\u0435 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043F\u043E\u043A\u0430 \u0435\u0449\u0435 \u0432 \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0435\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438! \u041D\u0443, \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E-\u0442\u0430\u043A\u0438 \u043E\u0431\u044B\u0447\u043D\u043E \u0437\u0430\u0431\u044B\u0432\u0430\u0442\u044C \u0435\u0433\u043E/\u0435\u0435 \u043F\u0440\u0438\u0440\u043E\u0434\u0443, \u0447\u0438\u0442\u0430\u044F \u0442\u0430\u043A\u043E\u0433\u043E \u0442\u0438\u043F\u0430 \u043F\u0438\u0441\u0430\u043D\u0438\u044F, \u0438 \u0442\u043E\u0433\u0434\u0430 \u043E\u043D \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442 \u0434\u0443\u043C\u0430\u0442\u044C, \u0447\u0442\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0435\u0441\u0442\u044C \u041A\u0442\u043E-\u0442\u043E, \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 &quot;\u0433\u0434\u0435-\u0442\u043E \u0435\u0449\u0435&quot; \u0432\u043E\u0432\u043D\u0435 \u0438\u043B\u0438 &quot;\u0433\u043B\u0443\u0431\u043E\u043A\u043E&quot; \u0432\u043D\u0443\u0442\u0440\u0438 (\u043A\u0430\u043A \u0433\u043B\u0443\u0431\u043E\u043A\u043E, \u043A\u043E\u0433\u0434\u0430 \u0442\u0435\u043B\u043E - \u0442\u0430\u043A\u043E\u0435 \u0442\u043E\u043D\u043A\u043E\u0435?), \u0438 \u0432\u0441\u0435 \u044D\u0442\u043E \u0441\u0443\u043C\u0430\u0441\u0448\u0435\u0441\u0442\u0432\u0438\u0435.</p></li><li><p>\u0415\u0441\u043B\u0438 \u0432\u044B \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442\u0435, \u0447\u0442\u043E \u0441 \u0432\u0430\u043C\u0438 \u043C\u043E\u0436\u0435\u0442 \u0441\u043B\u0443\u0447\u0438\u0442\u044C\u0441\u044F \u0441\u0435\u0440\u0434\u0435\u0447\u043D\u044B\u0439 \u043F\u0440\u0438\u0441\u0442\u0443\u043F, \u043D\u0435 \u0432\u043E\u043B\u043D\u0443\u0439\u0442\u0435\u0441\u044C, \u044F \u0441\u043F\u0435\u0448\u0443 \u043D\u0430 \u043F\u043E\u043C\u043E\u0449\u044C! \u0412\u043E-\u043F\u0435\u0440\u0432\u044B\u0445, \u043F\u043E\u0437\u0432\u043E\u043B\u044C\u0442\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C, \u0447\u0442\u043E \u044F \u0441\u0434\u0435\u043B\u0430\u043B: \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E\u0442 \u0441\u0430\u0439\u0442 \u0442\u0430\u043A\u0436\u0435 \u043E\u0431\u0443\u0447\u0430\u0435\u0442 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0443, \u044F \u0432\u044B\u0431\u0440\u0430\u043B &quot;\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u044B\u0439&quot; \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u0443\u0447\u0435\u043D\u0438\u043A\u0438 \u0443\u0437\u043D\u0430\u043B\u0438, \u043A\u0430\u043A \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0439 \u0442\u0435\u043A\u0441\u0442 \u043D\u0430\u043F\u0438\u0441\u0430\u043D \u043D\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435. \u0414\u0440\u0443\u0433\u0438\u043C \u0432\u0430\u0440\u0438\u0430\u043D\u0442\u043E\u043C \u043C\u043E\u0433 \u0431\u044B \u0431\u044B\u0442\u044C \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043E\u0442\u0440\u044B\u0432\u043A\u0430 \u0437\u0430 \u043E\u0442\u0440\u044B\u0432\u043A\u043E\u043C [\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, [\u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435,] \u0444\u0440\u0430\u0437\u0430 &quot;citta-sa\u1E45gha\u1E6D\u1E6D\u0101t&quot; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u043F\u0443\u0442\u0435\u043C \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u0438\u044F \u0431\u0435\u0441\u043F\u043E\u043A\u043E\u0439\u043D\u043E\u0433\u043E [\u0443\u043C\u0430] \u043D\u0430 \u042D\u0442\u043E\u043C--\u043D\u0430 \u0421\u0432\u0435\u0442\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F--&quot;]. \u0411\u0443\u0434\u044C\u0442\u0435 \u0443\u0432\u0435\u0440\u0435\u043D\u044B, \u0447\u0442\u043E \u044D\u0442\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043B\u0435\u0433\u0447\u0435 \u0447\u0438\u0442\u0430\u0442\u044C. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, &quot;\u044D\u0442\u043E \u043D\u0435 \u0441\u043E\u0432\u0441\u0435\u043C \u0442\u043E, \u0447\u0442\u043E \u043D\u0430\u043F\u0438\u0441\u0430\u043B \u0430\u0432\u0442\u043E\u0440&quot;. K\u1E63emar\u0101ja \u043E\u043F\u0438\u0441\u0430\u043B \u043A\u0430\u0436\u0434\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E, \u0430 \u043D\u0435 \u043E\u0442\u0440\u044B\u0432\u043E\u043A \u0437\u0430 \u043E\u0442\u0440\u044B\u0432\u043A\u043E\u043C. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044F \u0443\u0447\u0443 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0443 \u043A\u0440\u043E\u043C\u0435 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u0442\u0435\u043A\u0441\u0442\u043E\u0432, \u044F \u0432\u0441\u0435\u0433\u0434\u0430 \u0431\u0443\u0434\u0443 \u0432\u044B\u0431\u0438\u0440\u0430\u0442\u044C \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E, \u043D\u0430\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u044D\u0442\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E.</p></li></ol><p>\u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u044F \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u044E \u0441\u043E\u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0435 \u0441\u0435\u0439\u0447\u0430\u0441 \u0438 \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u044F \u0438\u0437\u0432\u043B\u0435\u043A\u0443 \u0430\u0431\u0437\u0430\u0446 \u0438\u0437 \u043C\u0430\u0441\u0441\u044B \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u043C\u0435\u044E\u0442\u0441\u044F \u043C\u0435\u0436\u0434\u0443 \u0434\u043B\u0438\u043D\u043D\u044B\u043C\u0438 \u0434\u0435\u0444\u0438\u0441\u0430\u043C\u0438 (\u2014...\u2014):</p><p>&quot;[\u0417\u0434\u0435\u0441\u044C] h\u1E5Bdaya --\u044F\u0434\u0440\u043E, \u0438\u043B\u0438 \u0441\u0435\u0440\u0434\u0446\u0435-- [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0421\u0432\u0435\u0442\u043E\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043E\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439. \u0412 \u044D\u0442\u043E\u043C [h\u1E5Bdaya], \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u0443\u043C\u0430, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 dar\u015Bana, [\u0438\u043B\u0438] \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u0445 \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u0432 [\u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445], \u0438 [\u0434\u0430\u0436\u0435] sv\u0101pa, [\u0438\u043B\u0438] \u043F\u0443\u0441\u0442\u043E\u0442\u044B, \u043A\u0430\u043A \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0442\u0435\u043B\u0430&quot;.</p><p>\u041D\u0443, \u0441\u0435\u0439\u0447\u0430\u0441 \u0430\u0431\u0437\u0430\u0446 \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 \u043F\u043E\u043D\u044F\u0442\u043D\u0435\u0439, \u0442\u0430\u043A \u0432\u0435\u0434\u044C? \u041E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u0441\u043C\u044B\u0441\u043B \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u043A\u043E\u0433\u0434\u0430 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u0443\u0435\u0442 \u0441\u0432\u043E\u0439 \u0443\u043C \u043D\u0430 \u0421\u0432\u0435\u0442\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u0430\u043C (\u0432 \u044F\u0434\u0440\u0435, \u0438\u043B\u0438 \u0441\u0435\u0440\u0434\u0446\u0435 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438) \u0432\u0441\u0435 \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u044B, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u043F\u0443\u0441\u0442\u043E\u0442\u0443, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u044E\u0442 \u043D\u0435 \u043E\u0442\u043B\u0438\u0447\u043D\u044B\u043C\u0438 (\u0442.\u0435. \u043A\u0430\u043A \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0442\u0435\u043B\u043E) \u043E\u0442 \u043D\u0435\u0433\u043E. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0432\u0441\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 \u0441\u043E \u0421\u0432\u0435\u0442\u043E\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u041C\u0443\u0434\u0440\u0435\u0446 \u0431\u0443\u0434\u0435\u0442 \u0432\u044B\u0440\u0430\u0436\u0430\u0442\u044C \u044D\u0442\u0443 \u0438\u0441\u0442\u0438\u043D\u0443 \u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0431\u0437\u0430\u0446\u0435. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u0442\u043E, \u0447\u0442\u043E \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043C\u0435\u0436\u0434\u0443 \u0434\u043B\u0438\u043D\u043D\u044B\u043C\u0438 \u0434\u0435\u0444\u0438\u0441\u0430\u043C\u0438, \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438.</p><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043F\u043E\u043C\u0438\u043C\u043E \u0442\u043E\u0433\u043E \u0444\u0430\u043A\u0442\u0430, \u0447\u0442\u043E \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0434\u0435\u043B\u0430\u0442\u044C \u0442\u0430\u043A\u043E\u0433\u043E \u0440\u043E\u0434\u0430 \u0438\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F, \u043F\u043E\u043C\u043D\u0438\u0442\u0435, \u0447\u0442\u043E \u044F \u0442\u0430\u043A\u0436\u0435 \u043E\u0431\u0443\u0447\u0430\u044E \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0443 \u043D\u0430 \u044D\u0442\u043E\u043C \u0432\u0435\u0431-\u0441\u0430\u0439\u0442\u0435 \u0438 &quot;\u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E&quot;, \u0447\u0442\u043E\u0431\u044B \u0443\u0447\u0435\u043D\u0438\u043A\u0438 \u0438\u0441\u043F\u044B\u0442\u0430\u043B\u0438 \u044D\u0442\u043E &quot;\u043A\u0430\u043A \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0432 \u044D\u0442\u043E\u043C \u0441\u0440\u0435\u0434\u043D\u0435\u0432\u0435\u043A\u043E\u0432\u043E\u043C \u0442\u0435\u043A\u0441\u0442\u0435&quot;, \u0442.\u0435. &quot;\u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0441\u043B\u043E\u0436\u043D\u043E!&quot;. \u041E\u0434\u043D\u043E \u0434\u0435\u043B\u043E, \u043A\u043E\u0433\u0434\u0430 \u0432\u044B \u0438\u0437\u0443\u0447\u0430\u0435\u0442\u0435 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442 \u0438\u0437 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u043A\u0438, \u0438 \u0441\u043E\u0432\u0441\u0435\u043C \u0434\u0440\u0443\u0433\u043E\u0435 \u0434\u0435\u043B\u043E, \u043A\u043E\u0433\u0434\u0430 \u0432\u044B \u0447\u0438\u0442\u0430\u0435\u0442\u0435 \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u044F, \u0433\u0434\u0435 \u0430\u0432\u0442\u043E\u0440\u044B &quot;\u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C&quot;, \u043D\u0435 \u0431\u0443\u0434\u0443\u0442 \u043F\u0438\u0441\u0430\u0442\u044C, \u043A\u0430\u043A \u043E\u0436\u0438\u0434\u0430\u0435\u0442\u0441\u044F. \u0414\u0430\u0436\u0435 \u0431\u043E\u043B\u0435\u0435 \u043F\u0440\u043E\u0434\u0432\u0438\u0442\u0443\u0442\u044B\u0435 \u0443\u0447\u0435\u0431\u043D\u0438\u043A\u0438 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u043A\u0438 \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u0432\u043A\u043B\u044E\u0447\u0430\u0442\u044C &quot;\u0432\u0441\u0435&quot; \u0441\u043F\u043E\u0441\u043E\u0431\u044B \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u0434\u043B\u044F \u043E\u0434\u043D\u043E\u0439 \u0438 \u0442\u043E\u0439 \u0436\u0435 \u0432\u0435\u0449\u0438 \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \u0434\u043B\u044F \u043F\u0440\u043E\u0441\u0442\u043E\u0433\u043E \u0432\u043E\u043F\u0440\u043E\u0441\u0430 \u043E \u0440\u0430\u0437\u043C\u0435\u0440\u0435 (\u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u043F\u043E\u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043B\u0438\u0441\u044C \u0431\u044B \u0442\u043E\u043C\u0430), \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0441\u0442\u0438\u043B\u0438 \u043C\u0435\u043D\u044F\u044E\u0442\u0441\u044F \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430. \u041D\u0435\u043E\u0442\u044A\u0435\u043C\u043B\u0435\u043C\u044B\u0435 \u0442\u0440\u0443\u0434\u043D\u043E\u0441\u0442\u0438 \u0432 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0435 \u0441\u0440\u0435\u0434\u043D\u0435\u0432\u0435\u043A\u043E\u0432\u043E\u0433\u043E \u0442\u0435\u043A\u0441\u0442\u0430, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0435\u0433\u043E\u0441\u044F \u043A \u0422\u0440\u0438\u043A\u0435, \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F \u043E\u0442 \u0442\u0435\u0445, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u044B \u043D\u0430\u0439\u0434\u0435\u0442\u0435 \u043F\u0440\u0438 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0435, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0431\u043E\u043B\u0435\u0435 \u0434\u0440\u0435\u0432\u043D\u0438\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u0439, \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u0434\u0440\u0443\u0433\u043E\u0439 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u0435. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043F\u0435\u0440\u0435\u0432\u043E\u0434 &quot;\u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E&quot; \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u043A\u0441\u0442\u0430, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C\u0443, \u044D\u0442\u043E \u0437\u0430\u0434\u0430\u0447\u0430, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u0430\u044F \u0441 &quot;\u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C\u0438&quot; \u0442\u0440\u0443\u0434\u043D\u043E\u0441\u0442\u044F\u043C\u0438, \u0441 \u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u0440\u0430\u043D\u043E \u0438\u043B\u0438 \u043F\u043E\u0437\u0434\u043D\u043E \u0441\u0442\u043E\u043B\u043A\u043D\u0435\u0442\u0441\u044F \u043B\u044E\u0431\u043E\u0439 \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u044B\u0439 \u0443\u0447\u0435\u043D\u0438\u043A, \u0438\u0437\u0443\u0447\u0430\u044E\u0449\u0438\u0439 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0439 \u044F\u0437\u044B\u043A. \u041F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0439\u0442\u0435 \u0447\u0438\u0442\u0430\u0442\u044C, \u043F\u043E\u0436\u0430\u043B\u0443\u0439\u0441\u0442\u0430.</p><ol start="4"><li>\u042F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u044D\u0442\u043E\u0442 \u0441\u043B\u043E\u0436\u043D\u044B\u0439 \u043F\u0440\u0435\u0434\u043C\u0435\u0442, \u0438\u043B\u0438 \u044D\u0442\u0430 \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0430 \u0431\u0443\u0434\u0435\u0442 \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0434\u043B\u0438\u043D\u043D\u043E\u0439, \u043D\u043E \u043C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u043F\u0438\u0441\u0430\u043B \u043E\u0431\u0448\u0438\u0440\u043D\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u0432 Svacchandatantra, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043E\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0441\u0435\u043A\u0440\u0435\u0442\u043D\u044B\u0439 \u0441\u043C\u044B\u0441\u043B \u044D\u0442\u043E\u0433\u043E \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430. \u041E\u043D \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442 \u044D\u0442\u043E\u0442 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u043A \u044D\u0442\u043E\u0439 310<sup>\u043E\u0439</sup> 5. \u0441\u0442\u0440\u043E\u0444\u0435, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0432 4<sup>\u043E\u043C</sup> pa\u1E6Dala (\u0440\u0430\u0437\u0434\u0435\u043B\u0435), \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044F \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435: &quot;\u090F\u0937\u0948\u0935 \u091A \u0928\u093F\u0930\u094D\u0935\u094D\u092F\u0941\u0924\u094D\u0925\u093E\u0928\u0938\u092E\u093E\u0927\u094D\u092F\u093E\u0924\u094D\u092E\u093E \u092E\u0939\u093E\u0930\u0939\u0938\u094D\u092F\u092D\u0942\u0924\u093E&quot; - &quot;E\u1E63aiva ca nirvyutth\u0101nasam\u0101dhy\u0101tm\u0101 mah\u0101rahasyabh\u016Bt\u0101||&quot;, \u0438\u043B\u0438 &quot;\u042D\u0442\u043E [\u043D\u0435\u0440\u0443\u0448\u0438\u043C\u043E\u0435 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 \u0432 \u0432\u044B\u0441\u0448\u0435\u043C Bhairava] \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u0442\u0430\u0439\u043D\u043E\u0439, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 Nirvyutth\u0101nasam\u0101dhi, \u0438\u043B\u0438 \u041F\u043E\u043B\u043D\u043E\u0439 \u041A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0439 vyutth\u0101na --\u043B\u044E\u0431\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043A\u0440\u043E\u043C\u0435 Sam\u0101dhi (\u041F\u043E\u043B\u043D\u043E\u0439 \u041A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438)--&quot;. \u041F\u043E\u0434\u0432\u043E\u0434\u044F \u0438\u0442\u043E\u0433\u0438: \u0422\u043E\u043B\u044C\u043A\u043E \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u044F \u0432 \u0413\u043E\u0441\u043F\u043E\u0434\u0435, \u0438&quot;\u043D\u0438\u043A\u043E\u0433\u0434\u0430&quot; \u043D\u0435 \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u043A \u043E\u0431\u044B\u0447\u043D\u043E\u043C\u0443 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F!</li></ol></div>',1),s=[o];function i(u,r,n,h,d,v){return m(),e("div",null,s)}var q=a(p,[["render",i]]);export{y as __pageData,q as default};
